body.script:
//
    const bareServerData = {
        "servers": [
            "https://wisp.rhw.one/api/bare",
            "https://phantomnetwork.cloud",
            "https://artclass.site",
            "https://shuttleproxy.com"
        ]
    };

    function populateDropdown() {
        const select = document.getElementById('bareServerSelect');
        bareServerData.servers.forEach((server) => {
            const option = document.createElement('option');
            option.value = server;
            option.textContent = server;
            select.appendChild(option);
        });
    }

    // Dynamic Context Binding and Hooking
    async function loadProxyService() {
        if (!('serviceWorker' in navigator)) return;

        try {
            const cdnWorkerUrl = 'https://cdn.jsdelivr.net/gh/zaka13alt/uvsvg@main/sw.js';
            console.log('Pre-fetching proxy core configuration...');

            const response = await fetch(cdnWorkerUrl);
            const scriptText = await response.text();

            // Create the local binary data asset directly from raw code
            const blob = new Blob([scriptText], { type: 'text/javascript' });
            const workerBlobUrl = URL.createObjectURL(blob);

            // Safely preserve and bind the native browser ServiceWorkerContainer registration reference
            const nativeRegister = navigator.serviceWorker.register.bind(navigator.serviceWorker);

            // Apply runtime interceptor mapping
            navigator.serviceWorker.register = async function(url, options) {
                console.log("Intercepted registration attempt. Target scope verified:", options.scope);

                // Route execution cleanly through native container using local memory blobs
                return nativeRegister(workerBlobUrl, { 
                    scope: options.scope || '/uv/service/' 
                });
            };

            console.log("Interception layer compiled. Ready for form initialization.");

        } catch (err) {
            console.error("Failed to map the remote worker execution pipeline:", err);
        }
    }

    window.addEventListener('load', () => {
        populateDropdown();
        loadProxyService();
    });
//
